A simple vertex transformation formula inside graphics hardware:

```hlsl
// HLSL Vertex Shader calculation
struct VS_INPUT {
    float4 Position : POSITION;
};

struct VS_OUTPUT {
    float4 Position : SV_POSITION;
};

cbuffer TransformBuffer : register(b0) {
    float4x4 WVPMatrix; // World-View-Projection composition matrix
};

VS_OUTPUT Main(VS_INPUT Input) {
    VS_OUTPUT Output;
    // Multiply local position by WVP matrix to project to clip space
    Output.Position = mul(Input.Position, WVPMatrix);
    return Output;
}
```
